mapper.insert:
merge into synlte.OBJECT_STORE_INFO a using (select #{item.tableId,jdbcType=VARCHAR} as tableId , #{item.tableName,jdbcType=VARCHAR} as tableName, #{item.storeType,jdbcType=INTEGER} as storeType, #{item.projectName,jdbcType=VARCHAR} as projectName, #{item.dataId,jdbcType=VARCHAR} as dataid ) b on ( upper(a.TABLEID) = upper(b.tableId) and upper(a.TABLENAME) = upper(b.tableName) and a.STORE_TYPE = b.storeType and upper(a.PROJECT_NAME) = upper(b.projectName) and upper(a.dataid) = upper(b.dataid)) when matched then update set TABLE_MOD_TIME = to_date(#{item.tableModTime,jdbcType=VARCHAR},'yyyy-MM-dd HH24:mi:ss')
, IMPORT_FLAG = #{item.importFlag,jdbcType=INTEGER}
when not matched then insert (TABLEID,TABLENAME,OBJECTNAME,STORE_TYPE,PROJECT_NAME,PROJECT_NAME_CN,MEMO, CREATER,CREATER_ID,TABLE_CREATE_TIME,TABLE_MOD_TIME,IMPORT_FLAG,DATAID,TABLEINFOID, ISPARTITION,SEARCHFLAG ) values( #{item.tableId,jdbcType=VARCHAR},#{item.tableName,jdbcType=VARCHAR}, #{item.objectName,jdbcType=VARCHAR},#{item.storeType,jdbcType=INTEGER}, #{item.projectName,jdbcType=VARCHAR},#{item.projectNameCh,jdbcType=VARCHAR}, #{item.memo,jdbcType=VARCHAR}, #{item.creater,jdbcType=VARCHAR}, #{item.createrId,jdbcType=VARCHAR},to_date(#{item.tableCreateTime,jdbcType=VARCHAR},'yyyy-MM-dd HH24:mi:ss'), to_date(#{item.tableModTime,jdbcType=VARCHAR},'yyyy-MM-dd HH24:mi:ss'), #{item.importFlag,jdbcType=INTEGER},#{item.dataId,jdbcType=VARCHAR},#{item.tableInfoId,jdbcType=VARCHAR}, #{item.isPartition,jdbcType=VARCHAR},#{item.searchFlag,jdbcType=VARCHAR} )

insert into synlte.OBJECT_STORE_FIELDINFO(ID,TABLEINFOID,FIELDID,COLUMNNAME,FIELDCHINEENAME,FIELDTYPE,FIELDLEN, DEFAULTVALUE,TABLEINDEX,INDEXTYPE,NEEDVALUE,RECNO,PARTITION_RECNO,CLUST_RECNO,COLUMNFIELDTYPE,COLUMNFIELDLEN) select * from(
select #{item.id},#{item.tableInfoId},#{item.fieldId,jdbcType=VARCHAR}, #{item.columnName},#{item.fieldChineeName,jdbcType=VARCHAR}, #{item.fieldType,jdbcType=INTEGER},#{item.fieldLen,jdbcType=INTEGER},#{item.defaultValue,jdbcType=VARCHAR}, #{item.tableIndex,jdbcType=INTEGER},#{item.indexType,jdbcType=INTEGER}, #{item.needValue,jdbcType=INTEGER},#{item.recno,jdbcType=INTEGER},#{item.partitionRecno,jdbcType=INTEGER}, #{item.clustRecno,jdbcType=INTEGER}, #{item.columnFieldType,jdbcType=INTEGER}, #{item.columnFieldLen,jdbcType=INTEGER}
) AS subquery

mapper.select:
select O.TABLEINFOID as tableInfoId, o2.objectname as objectName, o2.tableName as tableName, o.TABLEID as tableId, o2.SJZZYJFLVALLUE as organizationClassificationId, o.store_type as storeType, PROJECT_NAME as projectName, o.import_flag as importFlag, o.partitiontype as partitionType, o.lifecycle as lifeCycle, o2.tablename as standTableName, v.CENTER_NAME as centerName, v.res_name as resName, v.res_id as resId, o.TABLENAME as realTableName, CASE WHEN n.REGISTERCOUNT IS NULL THEN 0 ELSE n.REGISTERCOUNT end as registerCount, TABLE_CREATE_TIME as tableCreateTime, O.CREATER as creater from SYNLTE.OBJECT_STORE_INFO O left join (select ds.RES_ID, ds.RES_NAME, dc.CENTER_NAME from SYNDG.DS_DATA_RESOURCE ds left join syndg.ds_data_center dc on ds.CENTER_ID = dc.CENTER_ID) v on o.dataid = v.RES_ID left join (select TABLEINFOID, count(TABLEINFOID) AS REGISTERCOUNT from synlte.public_data_info GROUP BY TABLEINFOID) n on o.TABLEINFOID = n.TABLEINFOID left join synlte.object o2 on o2.tableid = o.tableid
(upper(o.OBJECTNAME) like upper(concat('%',concat(#{searchText},'%'))))
(upper(o2.tablename) like upper(concat('%',concat(#{searchText},'%'))))
(upper(o.TABLEID) like upper(concat('%',concat(#{searchText},'%'))))
(upper(o.TABLENAME) like upper(concat('%',concat(#{searchText},'%'))))
(upper(o.OBJECTNAME) like upper(concat('%',concat(#{searchText},'%')))) or (upper(o2.tablename) like upper(concat('%',concat(#{searchText},'%')))) or (upper(o.TABLEID) like upper(concat('%',concat(#{searchText},'%')))) or (upper(o.TABLENAME) like upper(concat('%',concat(#{searchText},'%'))))
and o.store_type in (
#{item}
)
and v.res_id in (
#{item}
)
and PROJECT_NAME in (
#{item}
)
and O.CREATER in (
#{item}
)
order by ${sort} ${sortOrder}

select count(0) from ds_project_table where upper(table_name_en)=upper(#{tableName})
and  project_name=#{projectName}
and  RES_ID= #{resId}
